class Solution:
    def uniqueXorTriplets(self, nums):
        vals = list(set(nums))
        res = set()
        m = len(vals)
        for i in range(m):
            for j in range(i, m):
                for k in range(j, m):
                    res.add(vals[i] ^ vals[j] ^ vals[k])
        return len(res)

