class Solution:
    def uniqueXorTriplets(self, nums):
        vals = list(set(nums))
        pair = set()
        for i in range(len(vals)):
            for j in range(i, len(vals)):
                pair.add(vals[i] ^ vals[j])
        res = set()
        for p in pair:
            for v in vals:
                res.add(p ^ v)
        return len(res)

