var uniqueXorTriplets = function(nums) {
    const vals = [...new Set(nums)];
    const pair = new Set();
    for (let i = 0; i < vals.length; i++)
        for (let j = i; j < vals.length; j++)
            pair.add(vals[i] ^ vals[j]);
    const res = new Set();
    for (const p of pair)
        for (const v of vals)
            res.add(p ^ v);
    return res.size;
};
